VALUES
  ('social-worker-moex-01181', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'J.Bradshaw的需求理論提供方案規劃者多種需求評量的方法，下列敘述何者正確？', '["運用資源盤點資料法所收集的資料可以有助於全面了解方案目標人口群的需求", "全國性調查可以在時間成本耗用最少的情況下確認民眾對需求的感受", "舉辦公聽會可以測得感受性需求，但卻存在著代表性是否足夠的爭議", "以現有研究資料進行差補外推法來進行需求評量，不需考量相關名詞操作性定義的不一致"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01182', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何者最能說明人群服務方案之「成效（effectiveness）」的意涵？', '["方案輸入與輸出之間的比例", "相對於方案的各項成本所能提供之服務的多寡", "服務對象在接受方案的服務過程或服務後所產生的改變", "為達成預定之目標或目的所事先安排好的一套活動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01183', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在社會服務組織中薪酬是激勵與維繫員工的重要因素，對於在薪酬制度上的設計，下列敘述何者錯誤？', '["薪酬內容應儘量單一性，比較明確可衡量", "薪酬制度要強化組織的社會形象", "薪酬制度應具公平性和適法性", "薪酬制度應可提高員工的組織承諾"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01184', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '危機管理對機構而言是重要的，對於危機特性的敘述，下列何者錯誤？', '["不確定性", "緊迫性", "複雜性", "單一負面性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01185', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織若決定要引進績效管理以提升效能時，需具備的認知和態度，何者錯誤？', '["認知績效管理就是一種選擇，量力而為選取項目的行動", "應該承認和接受任何績效是需要改善的", "沒有終點的旅程，持續的改善", "一定必須完成的行動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01186', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務方案的績效管理，有關於成果目標的具體（specific）是重要的，撰寫目標時應採用能使 情境產生可觀察變化的敘述，以下用詞何者較不適當？', '["改善", "減輕", "感受", "促進"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01187', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關社會服務「品質要素」的敘述，下列何者錯誤？', '["工作人員對服務對象有禮貌，抱著尊重體貼態度是保證性（assurance）", "服務易於被取得，距離近便是可近性（accessibility）", "工作人員領會服務對象需求，提供個別化關懷服務是同理心（empathy）", "以簡單語言告知服務使用者有關服務的訊息是可靠性（reliability）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01188', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '為某一特定任務而組成的團隊，其成員係建立在個人的專門技能和經驗，係屬於下列那一類的工 作團隊？', '["問題解決團隊", "專案團隊", "跨功能團隊", "自我管理團隊"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01189', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '契約委外之經費的取得已成為社福機構重要的財源之一，相較於非社會服務，有關社會服務契約 的特性，下列敘述何者錯誤？', '["服務對象經常為弱勢的民眾", "服務內容相對不具體且較複雜", "任務通常較為標準化", "績效監督難以進行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01190', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關社會服務行銷的特徵，下列敘述何者錯誤？', '["關心的是人、理念、價值和服務", "目標是追求公益使命的實現，超越財務的考量", "社會服務的利益往往與服務對象或捐贈者的支付有直接關聯", "成效很難標準化，品質難保證且不易衡量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
